"use client";

/**
 * useMe — single source of truth for the signed-in user + their accounts.
 *
 * Fetches /auth/me through the same-origin proxy. The result is what
 * tenant-scoped feature hooks read to know which `account_id` to send
 * (today: pick the first; later: account picker UI).
 */

import { useQuery } from "@tanstack/react-query";

export interface MeAccount {
  id: string;
  name: string;
  slug: string;
  role: string;
}

export interface Me {
  id: string;
  email: string | null;
  role: string;
  accounts: MeAccount[];
}

interface SuccessEnvelope<T> {
  ok: true;
  data: T;
  request_id: string;
}

export const meKeys = {
  me: ["auth", "me"] as const,
};

async function fetchMe(): Promise<Me> {
  const res = await fetch("/api/proxy/auth/me", {
    headers: { accept: "application/json" },
    cache: "no-store",
  });
  if (!res.ok) throw new Error(`me_request_failed_${res.status}`);
  const body = (await res.json()) as SuccessEnvelope<Me>;
  return body.data;
}

export function useMe() {
  return useQuery({
    queryKey: meKeys.me,
    queryFn: fetchMe,
    staleTime: 5 * 60_000,
  });
}
