/**
 * TanStack Query key factory for the data feature.
 *
 * Tuple-typed factory so TS catches accidental shape drift. Every key
 * is rooted at `["data"]` so `queryClient.invalidateQueries({ queryKey: dataKeys.all })`
 * cleanly nukes the whole feature's cache when the period/account
 * scope changes.
 */

import type {
  DataQueryParams,
  RevenueSeriesQueryParams,
  TopProductsQueryParams,
} from "../types/api";
import type { OrdersQueryParams } from "../types/orders";

export const dataKeys = {
  all: ["data"] as const,
  kpis: (p: DataQueryParams) => ["data", "kpis", p] as const,
  counts: (p: DataQueryParams) => ["data", "counts", p] as const,
  topProducts: (p: TopProductsQueryParams) => ["data", "top-products", p] as const,
  insights: (p: DataQueryParams) => ["data", "insights", p] as const,
  revenueSeries: (p: RevenueSeriesQueryParams) => ["data", "revenue-series", p] as const,
  orders: (p: OrdersQueryParams) => ["data", "orders", p] as const,
};
